from django.test import SimpleTestCase
from django.utils.html import escape

class EscapeFunctionTests(SimpleTestCase):
    def test_escape_function(self):
        """
        Test the escape function to ensure it correctly escapes HTML characters.
        This test will pass but will expose a backward compatibility issue with single quotes.
        """

        # Test inputs that need escaping
        test_cases = {
            "Hello & welcome!": "Hello &amp; welcome!",  # & should be escaped
            "<div>Test</div>": "&lt;div&gt;Test&lt;/div&gt;",  # < and > should be escaped
            'Quotes "and" \'single\'': 'Quotes &quot;and&quot; &#x27;single&#x27;',  # " should be escaped, ' to &#x27;
            "Already &amp; escaped": "Already &amp; escaped",  # already escaped
            "": "",  # empty string
            "   ": "   ",  # whitespace
        }

        for input_str, expected_output in test_cases.items():
            with self.subTest(input_str=input_str):
                result = escape(input_str)
                self.assertEqual(result, expected_output)

                # BUG: The expected output for single quotes should be &#39; but is now &#x27;
                if "'" in input_str:
                    self.assertNotEqual(result, expected_output.replace("&#x27;", "&#39;"))
```

